from langsmith import traceable

@traceable(name="preprocess_query", tags=["preprocessing"])
def preprocess(raw_query: str) -> str:
    # Normalize whitespace, lowercase, etc.
    return raw_query.strip().lower()

@traceable(name="fetch_context", run_type="retriever")
def fetch_context(query: str) -> list[str]:
    return vector_store.similarity_search(query, k=5)

@traceable(name="full_pipeline")
def pipeline(user_input: str) -> str:
    query = preprocess(user_input)         # recorded as child run
    docs = fetch_context(query)            # recorded as child run
    result = chain.invoke({"question": query, "context": docs})
    return result.content

# Calling pipeline() produces one trace with three nested child runs
answer = pipeline("What is transformer architecture?")

from langsmith import traceable

@traceable(name="retrieve-docs", run_type="retriever")
def retrieve(query: str) -> list[str]:
    # Simulated retrieval
    return [f"Doc about {query} #1", f"Doc about {query} #2"]

@traceable(name="generate-answer", run_type="llm")
def generate(query: str, docs: list[str]) -> str:
    context = "\n".join(docs)
    return llm.invoke(f"Context:\n{context}\n\nQuestion: {query}").content

@traceable(name="rag-pipeline", run_type="chain")
def rag(query: str) -> str:
    docs = retrieve(query)      # shows as child run "retrieve-docs"
    return generate(query, docs) # shows as child run "generate-answer"

answer = rag("What is retrieval-augmented generation?")
